def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        if bins[i] == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bins[i]
        if ratio > 1:
            priorities[i] = np.inf
        else:
            score = 0
            for power in range(1, 5):
                partial = ratio ** power
                if power % 2 == 0:
                    score += partial * np.log1p(bins[i])
                else:
                    score -= partial / np.sqrt(bins[i] + 1)
            if bins[i] < item * 2:
                score *= 2
            elif bins[i] > item * 10:
                score /= 2
            priorities[i] = score
    max_finite = np.max(priorities[np.isfinite(priorities)]) if np.any(np.isfinite(priorities)) else 1
    priorities[np.isinf(priorities)] = max_finite + 10
    return priorities
